 *
 * @returns A data URL of the image.
 * @public
 */
async toImageDataUrl(shapes: TLShapeId[] | TLShape[], opts: TLImageExportOptions = {}) {
	const { blob, width, height } = await this.toImage(shapes, opts)
	return {
		url: await FileHelpers.blobToDataUrl(blob),
		width,
		height,
	}
}

